+#[test]
+fn s3fifo_multi_owner_fairness_enforced() {
+    let mut policy = S3FifoPolicy::new(S3FifoConfig {
+        live_capacity: 8,
+        small_capacity: 4,
+        ghost_capacity: 8,
+        max_entries_per_owner: 2,
+        fallback_window: 16,
